#!/usr/bin/env node
// ============================================================================
// Block 4B-W-2A — Regenerate the pilot seed migration from the JSON manifest.
// ============================================================================
//
// Reads data/recent-sales-pilot-100.json and rewrites the VALUES block in
// migrations/2026-06-17-recent-sales-pilot-100.sql, preserving the file's
// header, post-condition checks, and structural comments.
//
// The migration uses sentinel markers:
//   -- BEGIN PILOT_ENTRIES (regenerated by scripts/regenerate-pilot-migration.mjs)
//   ...
//   -- END PILOT_ENTRIES
//
// Only the lines between those markers are replaced.
//
// Operator workflow:
//   1. Update data/recent-sales-pilot-100.json with real selections.
//   2. Run `node scripts/regenerate-pilot-migration.mjs`.
//   3. Diff the migration to confirm only the VALUES block changed.
//   4. Apply via Supabase SQL Editor.
// ============================================================================

import { readFile, writeFile } from 'node:fs/promises'
import { fileURLToPath } from 'node:url'
import { dirname, resolve } from 'node:path'

const __dirname  = dirname(fileURLToPath(import.meta.url))
const REPO_ROOT  = resolve(__dirname, '..')
const MANIFEST   = resolve(REPO_ROOT, 'data',       'recent-sales-pilot-100.json')
const MIGRATION  = resolve(REPO_ROOT, 'migrations', '2026-06-17-recent-sales-pilot-100.sql')

const BEGIN = '-- BEGIN PILOT_ENTRIES'
const END   = '-- END PILOT_ENTRIES'

function sqlEscape(s) {
  return String(s).replace(/'/g, "''")
}

function buildValuesBlock(entries) {
  const rows = entries.map((e, i) => {
    if (e.provider !== 'pricecharting') {
      throw new Error(`entry[${i}] provider must be 'pricecharting'`)
    }
    if (typeof e.provider_card_id !== 'string' || !/^[A-Za-z0-9_-]+$/.test(e.provider_card_id)) {
      throw new Error(`entry[${i}] provider_card_id invalid: ${e.provider_card_id}`)
    }
    if (typeof e.primary_category !== 'string') {
      throw new Error(`entry[${i}] primary_category missing`)
    }
    const reason = `pilot:${e.primary_category} - ${e.selection_reason ?? ''}`
    const comma  = i === entries.length - 1 ? '' : ','
    return `  ('pricecharting','${sqlEscape(e.provider_card_id)}',TRUE,'${sqlEscape(reason)}')${comma}`
  })
  return [
    `  ${BEGIN} (regenerated by scripts/regenerate-pilot-migration.mjs)`,
    ...rows,
    `  ${END}`,
  ].join('\n')
}

async function main() {
  const raw       = await readFile(MANIFEST, 'utf8')
  const manifest  = JSON.parse(raw)
  if (!Array.isArray(manifest.entries)) {
    throw new Error('manifest.entries is not an array')
  }
  const block = buildValuesBlock(manifest.entries)

  const sql       = await readFile(MIGRATION, 'utf8')
  const startIdx  = sql.indexOf(BEGIN)
  const endIdx    = sql.indexOf(END)
  if (startIdx === -1 || endIdx === -1) {
    throw new Error(`sentinels not found in ${MIGRATION}`)
  }

  // Find the start of the BEGIN line (back up to its leading whitespace).
  const lineStart = sql.lastIndexOf('\n', startIdx) + 1
  // Find the end of the END line.
  const lineEnd   = sql.indexOf('\n', endIdx)
  const lineEndIdx = lineEnd === -1 ? sql.length : lineEnd

  const next = sql.slice(0, lineStart) + block + sql.slice(lineEndIdx)
  await writeFile(MIGRATION, next, 'utf8')
  console.log(`OK: wrote ${manifest.entries.length} entries to ${MIGRATION}`)
}

main().catch(e => {
  console.error('FAIL:', e instanceof Error ? e.stack || e.message : String(e))
  process.exit(1)
})
